function t(key){
  const tbl = I18N[SETTINGS.lang] || I18N.fr;
  if (tbl[key]!=null) return tbl[key];
  if (I18N.en[key]!=null) return I18N.en[key];
  return (I18N.fr[key]!=null)? I18N.fr[key] : key;
}
const tr = t;   // alias i18n (évite la collision avec la variable locale t = temps)
const _t = t; // alias sûr là où `t` est masqué par une variable locale (ex. drawIntro)
function applyLang(){
  const L = SETTINGS.lang || 'fr';
  document.documentElement.lang = L;
  document.body.setAttribute('dir', L==='ar'? 'rtl':'ltr');
  document.querySelectorAll('[data-i18n]').forEach(el=>{ const v=t(el.dataset.i18n); if (typeof v==='string') el.textContent=v; });
  document.querySelectorAll('[data-i18n-ph]').forEach(el=>{ el.placeholder = t(el.dataset.i18nPh); });
  document.querySelectorAll('[data-i18n-html]').forEach(el=>{ el.innerHTML = t(el.dataset.i18nHtml); });
  const ls = document.getElementById('langSel'); if (ls) ls.value = L;
  if (typeof refreshOpts==='function') refreshOpts();
}
